function greetLog(name) {
    console.log('Hello, ' + name);
}

function greetReturn(name) {
    return 'Hello, ' + name;
}

let a = greetLog('Alex');
let b = greetReturn('Alex');

console.log('a is:', a);
console.log('b is:', b);

// Bonus: what happens here?
console.log('Length of b:', b.length);
console.log('Length of a:', a.length);

